export const 呼風玉符 = (bi) => {
    const u = bi.u, k = 2.4;
    const X = (c) => (c - 4.9) * k;
    const Z = (r) => (r - 0.6) * k + 1.2;
    const 抖 = (書, 寬 = 0.34) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 線 = (書, 寬 = 0.34) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    // 摺帶：連綿切返 n 摺自 rT 至 rB（距＝跨距/(n-1)；左起＝首摺自左端行右）
    const 摺 = (x0, x1, rT, rB, n, 左起 = true, 寬 = 0.4) => 抖(pa => {
        const p = n > 1 ? (rB - rT) / (n - 1) : 0;
        let dir = 左起 ? 1 : -1, y = rT;
        pa.M(X(dir > 0 ? x0 : x1), Z(y));
        for (let i = 0; i < n; i++) {
            const xe = dir > 0 ? x1 : x0;
            if (i < n - 1) {
                pa.L(X(xe - dir * p * 0.35), Z(y));
                pa.C(X(xe + dir * p * 1.05), Z(y - p * 0.05), X(xe + dir * p * 1.05), Z(y + p * 1.05), X(xe - dir * p * 0.35), Z(y + p));
                y += p;
                dir = -dir;
            }
            else
                pa.L(X(xe), Z(y));
        }
    }, 寬);
    // 頭・左疊帶（入鉤＋七摺＋短帶三摺＋左小鉤右曳尾）
    抖(p => p.M(X(2.35), Z(0.62)).C(X(2.05), Z(0.8), X(2.15), Z(1.02), X(2.45), Z(1.06)), 0.36);
    摺(0.55, 3.25, 1.25, 3.35, 7, false);
    摺(0.55, 2.2, 3.65, 4.25, 3, false);
    抖(p => p.M(X(0.78), Z(3.52)).C(X(0.52), Z(3.6), X(0.55), Z(3.85), X(0.8), Z(3.9)), 0.34);
    抖(p => p.M(X(2.25), Z(4.3)).C(X(2.55), Z(4.5), X(2.5), Z(4.72), X(2.2), Z(4.8)), 0.36);
    // 頭・中疊帶
    摺(3.45, 6.35, 1.1, 3.4, 8);
    摺(3.45, 5.15, 3.7, 4.35, 3);
    // 頭・右疊帶（四摺＋二摺左展＋短四摺綴 S 鉤・右緣波豎）
    摺(6.85, 9.35, 1.0, 2.15, 4);
    摺(5.6, 8.4, 2.5, 3.0, 2);
    摺(6.95, 8.35, 3.3, 4.35, 4);
    抖(p => p.M(X(8.55), Z(3.5)).C(X(9.15), Z(3.45), X(9.2), Z(3.98), X(8.62), Z(4.08))
        .C(X(8.32), Z(4.14), X(8.32), Z(4.34), X(8.56), Z(4.4)), 0.36);
    抖(p => p.M(X(9.42), Z(0.95)).C(X(9.55), Z(1.5), X(9.35), Z(2.1), X(9.5), Z(2.65)), 0.34);
    // 滿幅帶一（端く剔）
    摺(0.9, 9.3, 4.85, 6.95, 4);
    線(p => p.M(X(0.5), Z(6.75)).L(X(0.16), Z(7.0)).L(X(0.5), Z(7.25)), 0.34);
    線(p => p.M(X(9.5), Z(6.7)).L(X(9.84), Z(6.95)).L(X(9.5), Z(7.2)), 0.34);
    // 左右對疊帶一（跳莖相聯）
    摺(0.9, 4.75, 7.65, 9.35, 4);
    線(p => p.M(X(5.35), Z(7.9)).L(X(5.33), Z(9.3)), 0.36);
    摺(5.55, 9.2, 7.7, 9.4, 4);
    // 滿幅帶二（左く剔・小環結二）
    摺(0.9, 9.35, 9.55, 11.45, 5);
    線(p => p.M(X(0.55), Z(11.3)).L(X(0.2), Z(11.55)).L(X(0.55), Z(11.8)), 0.34);
    抖(p => p.M(X(4.25), Z(11.55)).C(X(4.5), Z(11.5), X(4.55), Z(11.72), X(4.3), Z(11.75)), 0.38);
    抖(p => p.M(X(4.55), Z(11.85)).C(X(4.8), Z(11.8), X(4.85), Z(12.02), X(4.6), Z(12.05)), 0.38);
    // 左右對疊帶二（密）
    摺(0.85, 4.65, 11.95, 13.75, 6);
    摺(5.5, 9.2, 12.0, 13.8, 6);
    // 滿幅帶三承大冂抱摺（臂外曳・角剔）
    摺(0.9, 9.4, 13.95, 14.6, 2);
    線(p => p.M(X(1.3), Z(16.95)).L(X(1.3), Z(15.05)).L(X(8.95), Z(15.0)).L(X(8.95), Z(16.85)), 0.42);
    摺(1.75, 8.6, 15.35, 16.6, 4);
    線(p => p.M(X(1.55), Z(15.35)).L(X(1.85), Z(15.6)), 0.32);
    線(p => p.M(X(8.65), Z(15.3)).L(X(8.35), Z(15.55)), 0.32);
    抖(p => p.M(X(0.6), Z(15.55)).C(X(0.5), Z(16.2), X(0.55), Z(16.9), X(0.85), Z(17.45)), 0.38);
    抖(p => p.M(X(9.55), Z(15.5)).C(X(9.65), Z(16.15), X(9.6), Z(16.85), X(9.3), Z(17.4)), 0.38);
    // 滿幅帶四＋密疊帶夾中莖
    摺(1.0, 9.35, 17.3, 18.35, 3);
    摺(1.0, 4.6, 18.6, 20.25, 5);
    線(p => p.M(X(4.95), Z(18.5)).L(X(4.93), Z(20.3)), 0.36);
    摺(5.6, 9.2, 18.65, 20.3, 5);
    // 底帶承丫莖
    摺(1.0, 9.3, 20.45, 21.15, 2);
    摺(1.0, 9.3, 21.5, 22.9, 3);
    線(p => p.M(X(5.2), Z(21.45)).L(X(5.18), Z(22.3)), 0.36);
    抖(p => p.M(X(5.18), Z(22.3)).L(X(4.55), Z(22.85)), 0.36);
    抖(p => p.M(X(5.22), Z(22.3)).L(X(5.85), Z(22.85)), 0.36);
    摺(1.0, 9.2, 22.95, 23.65, 2);
    // 己足對
    抖(p => p.M(X(1.35), Z(23.7))
        .C(X(1.3), Z(24.15), X(1.2), Z(24.45), X(1.05), Z(24.65))
        .C(X(0.95), Z(24.9), X(1.28), Z(24.98), X(1.42), Z(24.75))
        .C(X(1.48), Z(24.55), X(1.3), Z(24.45), X(1.2), Z(24.58)), 0.38);
    抖(p => p.M(X(9.05), Z(23.7))
        .C(X(9.15), Z(24.12), X(9.28), Z(24.4), X(9.33), Z(24.58))
        .C(X(9.4), Z(24.85), X(9.05), Z(24.92), X(8.97), Z(24.68))
        .C(X(8.92), Z(24.5), X(9.1), Z(24.4), X(9.2), Z(24.52)), 0.38);
};
